export const AddRowAbove: FC<AddRowAboveProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? AddRowAboveLight : AddRowAboveDark;

